export interface ProductImage {
  id: string;
  originalFile: File;
  originalPreview: string;
  resultUrl?: string;
  status: 'idle' | 'processing' | 'completed' | 'error';
  error?: string;
}

export interface ProcessingConfig {
  prompt: string;
  aspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

export enum ImageStatus {
  IDLE = 'idle',
  PROCESSING = 'processing',
  COMPLETED = 'completed',
  ERROR = 'error'
}

import { GoogleGenAI } from "@google/genai";

const MODEL_NAME = 'gemini-2.5-flash-image';

export const processImageWithGemini = async (
  base64Image: string,
  prompt: string,
  aspectRatio: string = "1:1"
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `
    You are a professional product photographer and creative director. 
    Your task is to take a product image with a white or plain background and transform it into a high-end, realistic lifestyle photograph.
    Maintain the scale, texture, and details of the original product perfectly. 
    The lighting in the new scene should realistically interact with the product.
    Do not add text or extra branding to the image.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image.split(',')[1], // Remove metadata prefix
              mimeType: 'image/png',
            },
          },
          {
            text: `${prompt}. Ensure the final result is a professional lifestyle photo. Keep the original product exactly as it is, just change the background and environment.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio as any,
        }
      }
    });

    let resultImageUrl = '';

    // Iterate through response parts to find the image part
    if (response.candidates && response.candidates[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          resultImageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
    }

    if (!resultImageUrl) {
      throw new Error("No image was generated by the model.");
    }

    return resultImageUrl;
  } catch (error: any) {
    console.error("Gemini Image processing error:", error);
    throw new Error(error.message || "Failed to process image");
  }
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = (error) => reject(error);
  });
};

