    for (const img of images) {
      if (img.status === 'completed') continue;

      setImages(prev => prev.map(p => p.id === img.id ? { ...p, status: 'processing', error: undefined } : p));

      try {
        const base64 = await fileToBase64(img.originalFile);
        const resultUrl = await processImageWithGemini(base64, config.prompt, config.aspectRatio);

        setImages(prev => prev.map(p => p.id === img.id ? { 
          ...p, 
          status: 'completed', 
          resultUrl 
        } : p));
      } catch (err: any) {
        setImages(prev => prev.map(p => p.id === img.id ? { 
          ...p, 
          status: 'error', 
          error: err.message || "Model failed" 
        } : p));
      }
