                    className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none resize-none h-32"
                    placeholder="Describe the environment (e.g., 'Modern kitchen', 'Cozy bedroom with soft lighting')..."
                  />
                  <p className="mt-2 text-[10px] text-gray-400 italic">
                    Describe the background, lighting, and mood. The AI will preserve your product.
                  </p>
                </div>

                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2">
                    Aspect Ratio
                  </label>
                  <div className="grid grid-cols-3 gap-2">
                    {(['1:1', '4:3', '16:9', '3:4', '9:16'] as const).map((ratio) => (
                      <button
                        key={ratio}
                        onClick={() => setConfig({ ...config, aspectRatio: ratio })}
                        className={`py-2 rounded-lg text-xs font-bold border transition-all ${
                          config.aspectRatio === ratio 
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                          : 'bg-white border-gray-200 text-gray-600 hover:border-indigo-300'
                        }`}
                      >
                        {ratio}
                      </button>
