                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="bg-indigo-600 text-white px-8 py-4 rounded-2xl text-sm font-bold hover:bg-indigo-700 transition-all shadow-xl hover:shadow-indigo-200 active:scale-95 flex items-center space-x-3"
