                      <div className="flex flex-col items-center">
                        <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400 mb-2">Step 3</span>
                        <div className="w-12 h-12 bg-indigo-200 rounded-lg flex items-center justify-center">
                          <i className="fas fa-magic text-indigo-600"></i>
                        </div>
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6">
                    {images.map((img) => (
                      <ImageCard 
                        key={img.id} 
                        image={img} 
                        onRemove={removeImage} 
                      />
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Footer Mobile/Compact Call to Action */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 lg:hidden z-50 shadow-2xl">
         <button 
            onClick={processBulk}
            disabled={idleCount === 0 || isBulkProcessing}
            className={`w-full py-4 rounded-xl text-sm font-bold flex items-center justify-center space-x-2 transition-all shadow-lg ${
              idleCount === 0 || isBulkProcessing
              ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
              : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
            }`}
          >
            {isBulkProcessing ? (
              <>
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                <span>Processing...</span>
              </>
            ) : (
              <>
                <i className="fas fa-bolt"></i>
                <span>Generate {idleCount} Images</span>
              </>
            )}
          </button>
      </div>
    </div>
  );
};

